using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---

var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// With a default resolver every type resolves, so use a context that
// only knows about Person to show both the success and failure paths.
var restricted = new JsonSerializerOptions
{
    TypeInfoResolver = PersonContext.Default
};

if (restricted.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded — Type: {found!.Type.Name}");
}

// UnknownType is NOT in the source-gen context, so this returns false.
if (restricted.TryGetTypeInfo<UnknownType>(out JsonTypeInfo<UnknownType>? missing))
{
    Console.WriteLine("This should not print.");
}
else
{
    Console.WriteLine("TryGetTypeInfo<UnknownType> returned false — no exception thrown.");
}

// --- Types ---

public record Person(string Name, int Age);

public class UnknownType { public int X { get; set; } }

[JsonSerializable(typeof(Person))]
public partial class PersonContext : JsonSerializerContext;

